
export default class Logger {
  isLog: boolean
  name: string
  constructor(name: string, isLog?: boolean) {
    this.isLog = isLog || false
    this.name = name || ''
  }
  info(message: string) {
    if (this.isLog) {
      console.log('%c %s', 'color: yellow; background-color: black;', `[AppLog WEB SDK] [instance: ${this.name}]` + ' ' + message);
    }
  }
  warn(message: string) {
    if (this.isLog) {
      console.warn(`[AppLog WEB SDK] [instance: ${this.name}]` + ' ' + message);
    }
  }
  error(message: string) {
    if (this.isLog) {
      console.error(`[AppLog WEB SDK] [instance: ${this.name}]` + ' ' + message);
    }
  }
  throw(msg: string) {
    this.error(this.name)
    throw new Error(msg)
  }
}